from collections import deque

def bfs(start, neighbors, target=None):
    q = deque([(start, 0)])
    seen = {start}
    while q:
        node, dist = q.popleft()
        if node == target:
            return dist
        for nb in neighbors(node):
            if nb not in seen:
                seen.add(nb)
                q.append((nb, dist + 1))
    return -1   # unreachable

import heapq

def dijkstra(start, neighbors):
    pq = [(0, start)]                 # (distance, node)
    dist = {start: 0}
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]: continue       # stale entry
        for v, w in neighbors(u):      # w >= 0
            nd = d + w
            if nd < dist.get(v, float('inf')):
                dist[v] = nd
                heapq.heappush(pq, (nd, v))
    return dist

def backtrack(state, choices, is_valid, is_complete, record):
    if is_complete(state):
        record(state)
        return
    for c in choices(state):
        state.append(c)
        if is_valid(state):
            backtrack(state, choices, is_valid, is_complete, record)
        state.pop()

def build_prefix(arr):
    pre = [0] * (len(arr) + 1)
    for i, x in enumerate(arr):
        pre[i + 1] = pre[i] + x
    return pre

def range_sum(pre, l, r):
    '''Sum of arr[l:r] in O(1) after an O(n) build.'''
    return pre[r] - pre[l]

pre = build_prefix([1, 2, 3, 4, 5])
print(range_sum(pre, 1, 4))   # 9  (2+3+4)
